def calc_landscaping_cost(services):
    rates = {
        "Lawn Mowing": 50,
        "Tree Trimming": 60,
        "Flower Planting": 40,
        "General Cleanup": 30
    }
    total = 0.0
    for svc, hrs in services:
        if svc in rates:
            total += rates[svc] * hrs
    return total * 0.8
